```
def check_test_log(item):
   caplog = item.catch_log_handler
    for record in caplog.records:
        if (record.levelno >= logging.WARNING and
            not getattr(record, 'checklogs_ignore', False)):
            raise AssertionError('Logger received warning messages')

@pytest.hookimpl(trylast=True)
def pytest_runtest_setup(item):
    check_test_log(item)
@pytest.hookimpl(trylast=True)
def pytest_runtest_call(item):
    check_test_log(item)
@pytest.hookimpl(trylast=True)
def pytest_runtest_teardown(item, nextitem):
    check_test_log(item)
```

This also works with the catchlog functionality that has now been merged into pytest main.

